const coupons = [];

function redeemCoupon(code) {
  const coupon = coupons.find(c => c.code === code);

  if (!coupon) {
    throw new Error('Invalid coupon code.');
  }

  if (coupon.expired) {
    throw new Error('Coupon has expired.');
  }

  if (coupon.used) {
    throw new Error('Coupon has already been used.');
  }

  coupon.used = true;

  // Apply discount to cart total
  // ...

  return coupon;
}

// Handle high traffic during sales events
const concurrentRedemptions = new Set();

function redeemCouponWithConcurrencyControl(code) {
  if (concurrentRedemptions.has(code)) {
    throw new Error('Coupon is being redeemed concurrently.');
  }

  concurrentRedemptions.add(code);

  try {
    return redeemCoupon(code);
  } finally {
    concurrentRedemptions.delete(code);
  }
}